class PaymentProcessor(private val context: Context) {
    private val billingClient: BillingClient = BillingClient.newBuilder(context)
        .setListener(purchasesUpdatedListener)
        .enablePendingPurchases()
        .build()

    private val encryptedPrefs: SharedPreferences
    private val secureRandom = SecureRandom()
    private val isInitialized = AtomicBoolean(false)
    private val deviceIntegrityChecker = DeviceIntegrityChecker(context)

    init {
        val masterKeyAlias = MasterKeys.getOrCreate(MasterKeys.AES256_GCM_SPEC)
        encryptedPrefs = EncryptedSharedPreferences.create(
            context,
            "payment_prefs",
            masterKeyAlias,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    private val purchasesUpdatedListener = PurchasesUpdatedListener { _, purchases ->
        purchases?.forEach { purchase ->
            if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
                handlePurchase(purchase)
            }
        }
    }

    fun initialize() {
        if (isInitialized.get()) return
        deviceIntegrityChecker.performIntegrityCheck()
        billingClient.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(billingResult: BillingResult) {
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    isInitialized.set(true)
                }
            }

            override fun onBillingServiceDisconnected() {
                isInitialized.set(false)
            }
        })
    }

    fun purchaseProduct(sku: String, productType: String) {
        if (!isInitialized.get()) return
        val billingFlowParams = BillingFlowParams.newBuilder()
            .setProductDetailsParamsList(
                listOf(
                    BillingFlowParams.ProductDetailsParams.newBuilder()
                        .setProductDetails(getProductDetails(sku))
                        .build()
                )
            )
            .build()
        billingClient.launchBillingFlow(context, billingFlowParams)
    }

    private fun getProductDetails(sku: String): ProductDetails {
        return ProductDetails.newBuilder()
            .setProductId(sku)
            .setProductType(productType)
            .build()
    }

    private fun handlePurchase(purchase: Purchase) {
        val purchaseToken = purchase.purchaseToken
        val signature = purchase.signature
        val sku = purchase.products.first()
        val encryptedData = encryptData("$sku:$purchaseToken:$signature")
        encryptedPrefs.edit()
            .putString("purchase_$sku", encryptedData)
            .apply()
    }

    private fun encryptData(data: String): String {
        val keyGenerator = KeyGenerator.getInstance("AES")
        keyGenerator.init(256)
        val secretKey = keyGenerator.generateKey()
        val cipher = Cipher.getInstance("AES/GCM/NoPadding")
        cipher.init(Cipher.ENCRYPT_MODE, secretKey)
        val encrypted = cipher.doFinal(data.toByteArray())
        return Base64.encodeToString(encrypted, Base64.DEFAULT)
    }

    fun processWalletTransaction(amount: Double, walletId: String) {
        if (!deviceIntegrityChecker.isDeviceSecure()) {
            throw SecurityException("Device integrity check failed")
        }
        val transactionId = generateTransactionId()
        val encryptedAmount = encryptData(amount.toString())
        val encryptedWalletId = encryptData(walletId)
        encryptedPrefs.edit()
            .putString("wallet_$transactionId", "$encryptedAmount:$encryptedWalletId")
            .apply()
    }

    private fun generateTransactionId(): String {
        val bytes = ByteArray(16)
        secureRandom.nextBytes(bytes)
        return Base64.encodeToString(bytes, Base64.NO_WRAP)
    }

    fun getPurchaseHistory(sku: String): String? {
        return encryptedPrefs.getString("purchase_$sku", null)
    }

    fun cleanup() {
        billingClient.endConnection()
    }
}

class DeviceIntegrityChecker(private val context: Context) {
    private val isSecure = AtomicBoolean(false)

    fun performIntegrityCheck() {
        val isEmulator = detectEmulator()
        val isRooted = detectRoot()
        val isDebuggable = context.applicationInfo.flags and android.content.pm.ApplicationInfo.FLAG_DEBUGGABLE != 0
        val isTampered = detectTampering()
        
        isSecure.set(!isEmulator && !isRooted && !isDebuggable && !isTampered)
    }

    private fun detectEmulator(): Boolean {
        return android.os.Build.FINGERPRINT.startsWith("sdk_gphone")
    }

    private fun detectRoot(): Boolean {
        return try {
            val files = arrayOf(
                "/system/app/Superuser.apk",
                "/sbin/su",
                "/system/bin/su",
                "/system/xbin/su",
                "/data/local/xbin/su",
                "/data/local/bin/su",
                "/system/sd/xbin/su",
                "/system/bin/failsafe/su",
                "/data/local/su"
            )
            files.any { android.os.FileUtils.getFileStreamPath(it).exists() }
        } catch (e: Exception) {
            false
        }
    }

    private fun detectTampering(): Boolean {
        return try {
            val packageInfo = context.packageManager.getPackageInfo(context.packageName, 0)
            val signature = packageInfo.signatures[0].toByteArray()
            val expectedSignature = "expected_signature_hash"
            !signature.contentEquals(expectedSignature.toByteArray())
        } catch (e: Exception) {
            false
        }
    }

    fun isDeviceSecure(): Boolean = isSecure.get()
}